  user=state.users.find(u=>u.email===email&&u.active);
  if(!user)throw new Error("Usuário não encontrado ou inativo.");
  if(user.id===1&&password!=="Atlas@2026")throw new Error("Senha inválida.");
  state.currentUser=user;
