function renderDashboard(){renderExecutiveDashboard();const counts={open:state.issues.filter(i=>i.status==="Aberta").length,treatment:state.issues.filter(i=>i.status==="Em tratamento"||i.status==="Rejeitada").length,approval:state.issues.filter(i=>i.status==="Aguardando validação").length,closed:state.issues.filter(i=>i.status==="Baixada").length};$("#summaryGrid").innerHTML=`<article class="metric"><div class="metric-head"><span>Abertas</span><i class="metric-icon">○</i></div><strong>${counts.open}</strong><small><b>1.806</b> na base para migração</small></article><article class="metric"><div class="metric-head"><span>Em tratamento</span><i class="metric-icon">↻</i></div><strong>${counts.treatment}</strong><small>Com a contratada</small></article><article class="metric"><div class="metric-head"><span>Aguardando validação</span><i class="metric-icon">✓</i></div><strong>${counts.approval}</strong><small>Na fila dos fiscais</small></article><article class="metric"><div class="metric-head"><span>Baixadas</span><i class="metric-icon">↓</i></div><strong>${counts.closed}</strong><small>Com histórico completo</small></article>`;
 const attention=state.issues.filter(i=>i.status!=="Baixada").slice(0,4);$("#attentionList").innerHTML=attention.map(i=>`<button class="issue-row text-btn" data-issue="${i.id}"><img class="issue-thumb" src="${i.before}" alt="Evidência da pendência"><div style="text-align:left"><h4>#${i.id} · ${i.type}</h4><p>${i.asset} · ${i.company} · prazo ${formatDate(i.deadline)}</p></div><span class="status ${statusClass(i.status)}">${i.status}</span></button>`).join("");
 const statuses=["Aberta","Em tratamento","Aguardando validação","Rejeitada","Baixada"];const colors=["#f89b32","#3578bc","#6fa2d2","#b7403b","#18324d"];$("#statusChart").innerHTML=statuses.map((s,k)=>{const n=state.issues.filter(i=>i.status===s).length;return `<div class="chart-row"><span>${s}</span><strong>${n}</strong><div class="chart-track"><span style="width:${n/state.issues.length*100}%;background:${colors[k]}"></span></div></div>`}).join("");
 $("#activityList").innerHTML=state.issues.slice(0,3).map((i,k)=>`<div class="activity"><div class="activity-icon">${k===0?"✓":k===1?"↻":"+"}</div><div><p><strong>${i.history.at(-1)}</strong><br>na pendência #${i.id}</p><small>Hoje, ${9+k}:2${k}</small></div></div>`).join("");bindIssueLinks()}

function setFilterOptions(selector,label,values){const element=$(selector),selected=element.value;element.innerHTML=`<option value="">${label}</option>`+values.filter(Boolean).sort((a,b)=>a.localeCompare(b,"pt-BR")).map(value=>`<option>${value}</option>`).join("");element.value=selected}
function renderIssues(){setFilterOptions("#statusFilter","Todos os status",[...new Set(state.issues.map(i=>i.status))]);setFilterOptions("#typeFilter","Todos os tipos",[...new Set(state.issues.map(i=>i.type))]);setFilterOptions("#companyFilter","Todas as empresas",[...new Set(state.issues.map(i=>i.company))]);setFilterOptions("#assetFilter","Todos os ativos",[...new Set(state.issues.map(i=>i.asset))]);setFilterOptions("#classificationFilter","Todas as classificações",[...new Set(state.issues.map(i=>i.classification))]);setFilterOptions("#ownerFilter","Todos os responsáveis FICO",[...new Set(state.issues.map(i=>i.owner).filter(i=>i!=="Não atribuído"))]);filterIssues()}
function activeFilters(){return {q:$("#issueSearch").value.trim(),status:$("#statusFilter").value,specialty:$("#typeFilter").value,company:$("#companyFilter").value,asset:$("#assetFilter").value,classification:$("#classificationFilter").value,fico_owner:$("#ownerFilter").value,opened_from:$("#openedFromFilter").value,opened_to:$("#openedToFilter").value}}
function reportQuery(ignoreCompany=false){const params=new URLSearchParams();for(const [key,value] of Object.entries(activeFilters()))if(value&&!(ignoreCompany&&key==="company"))params.set(key,value);return params.toString()?`?${params}`:""}
function filterIssues(){const f=activeFilters(),q=f.q.toLowerCase();const rows=state.issues.filter(i=>(!q||JSON.stringify(i).toLowerCase().includes(q))&&(!f.status||i.status===f.status)&&(!f.specialty||i.type===f.specialty)&&(!f.company||i.company===f.company)&&(!f.asset||i.asset===f.asset)&&(!f.classification||i.classification===f.classification)&&(!f.fico_owner||i.owner===f.fico_owner)&&(!f.opened_from||i.openedAt>=f.opened_from)&&(!f.opened_to||i.openedAt<=f.opened_to));$("#issuesTable").innerHTML=rows.map(i=>`<tr class="clickable" data-issue="${i.id}"><td><strong>#${i.id}</strong><small>${i.classification}</small></td><td><strong>${i.type}</strong><small>${i.description.slice(0,58)}${i.description.length>58?"…":""}</small></td><td><strong>${i.asset}</strong><small>${i.km}</small></td><td>${i.company}</td><td>${formatDate(i.deadline)}</td><td><span class="status ${statusClass(i.status)}">${i.status}</span></td><td><button class="row-action">Abrir</button></td></tr>`).join("");bindIssueLinks()}
[$("#issueSearch"),$("#statusFilter"),$("#typeFilter"),$("#companyFilter"),$("#assetFilter"),$("#classificationFilter"),$("#ownerFilter"),$("#openedFromFilter"),$("#openedToFilter")].forEach(el=>el.addEventListener(el.tagName==="INPUT"?"input":"change",filterIssues));
$("#clearFiltersBtn").addEventListener("click",()=>{$("#issueSearch").value="";["#statusFilter","#typeFilter","#companyFilter","#assetFilter","#classificationFilter","#ownerFilter","#openedFromFilter","#openedToFilter"].forEach(selector=>$(selector).value="");filterIssues()});

function renderApprovals(){const eligible=state.issues.filter(i=>i.status==="Aguardando validação"&&(state.currentUser.role==="Administrador"||canApprove(i)));$("#approvalNotice").innerHTML=state.currentUser.globalApproval?"Você possui <strong>aprovação geral</strong>. Abra cada pendência e revise os dados e as duas evidências antes de decidir.":`Sua alçada atual: <strong>${state.currentUser.specialties.join(", ")||"sem especialidades de aprovação"}</strong>.`;$("#approvalCards").innerHTML=eligible.length?eligible.map(i=>`<article class="approval-review-card"><header class="approval-review-head"><div><span class="approval-id">#${i.id}</span><span class="status validacao">Aguardando validação</span></div><span class="approval-classification">${i.classification}</span></header><div class="approval-review-images"><figure><figcaption>Antes · condição registrada</figcaption><img src="${i.before}" alt="Foto de abertura da pendência ${i.id}"></figure><figure><figcaption>Depois · correção informada</figcaption><img src="${i.after}" alt="Foto da correção da pendência ${i.id}"></figure></div><div class="approval-review-content"><div><p class="eyebrow">${i.company} · ${i.type}</p><h3>${i.asset} · ${i.km}</h3><p class="approval-description">${i.description}</p></div><dl class="approval-facts"><div><dt>Prazo</dt><dd>${formatDate(i.deadline)}</dd></div><div><dt>Fiscal FICO</dt><dd>${i.owner}</dd></div><div><dt>Contratada</dt><dd>${i.contractor}</dd></div><div><dt>Segmento</dt><dd>${i.segment||"Não informado"}</dd></div></dl></div><footer class="approval-review-footer"><span>A decisão fica disponível somente após abrir a análise completa.</span><button class="btn primary" type="button" data-review="${i.id}">Analisar pendência</button></footer></article>`).join(""):'<div class="panel"><h3>Fila concluída</h3><p class="muted">Não há pendências aguardando sua validação.</p></div>';$$('[data-review]').forEach(button=>button.onclick=()=>openIssue(+button.dataset.review))}
async function completeDecision(id,approved,comment=""){const i=state.issues.find(x=>x.id===id);if(!canApprove(i)&&state.currentUser.role!=="Administrador"){throw new Error("Seu perfil não possui alçada para esta pendência.")}if(API_ENABLED){const response=await api(`/issues/${id}/decision`,{method:"POST",body:JSON.stringify({decision:approved?"approve":"reject",comment,confirmed_review:approved,...issueVersion(i)})});if(response.queued){i.status=approved?"Baixada":"Rejeitada";i.history.push(`${approved?"Baixa aguardando sincronização":"Rejeição aguardando sincronização"}: ${comment}`)}else await hydrateFromApi()}else{i.status=approved?"Baixada":"Rejeitada";i.history.push(`${approved?"Baixa aprovada":"Correção rejeitada"} por ${state.currentUser.name}${comment?`: ${comment}`:""}`);save()}renderAll();await updateSyncStatus();toast(navigator.onLine?(approved?`Pendência #${id} baixada com sucesso.`:`Pendência #${id} devolvida à contratada.`):"Operação salva no aparelho e aguardando conexão.")}
function openApprovalConfirmation(issue){const form=$("#approvalForm");form.reset();form.elements.issueId.value=issue.id;$("#approvalConfirmationSummary").innerHTML=`<div class="approval-final-head"><div><strong>Pendência #${issue.id} · ${issue.type}</strong><span>${issue.company} · ${issue.asset} · ${issue.km}</span></div><span class="status validacao">Aguardando validação</span></div><div class="approval-final-images"><figure><figcaption>Antes</figcaption><img src="${issue.before}" alt="Condição inicial da pendência ${issue.id}"></figure><figure><figcaption>Depois</figcaption><img src="${issue.after}" alt="Condição após a correção da pendência ${issue.id}"></figure></div><div class="approval-final-description"><small>Descrição da pendência</small><p>${issue.description}</p></div><dl class="approval-final-facts"><div><dt>Classificação</dt><dd>${issue.classification}</dd></div><div><dt>Prazo</dt><dd>${formatDate(issue.deadline)}</dd></div><div><dt>Fiscal</dt><dd>${issue.owner}</dd></div><div><dt>Contratada</dt><dd>${issue.contractor}</dd></div></dl>`;$("#approvalDialog").showModal()}
async function decide(id,approved){const issue=state.issues.find(item=>item.id===id);if(!approved){$("#decisionForm").elements.issueId.value=id;$("#decisionDialog").showModal();return}openApprovalConfirmation(issue)}

function openAdminPasswordReset(user){const form=$("#resetPasswordForm");form.reset();form.elements.userId.value=user.id;$("#resetPasswordSummary").innerHTML=`<strong>${user.name}</strong><br>${user.email} · ${user.company}`;$("#resetPasswordDialog").showModal()}
function renderUsers(){const requests=state.passwordResetRequests,panel=$("#passwordResetPanel");panel.classList.toggle("hidden",!requests.length);panel.innerHTML=requests.length?`<div><p class="eyebrow">Recuperação de acesso</p><h3>${requests.length} solicitação${requests.length===1?"":"ões"} aguardando atendimento</h3></div><div class="reset-request-list">${requests.map(request=>`<button type="button" data-request-reset="${request.user_id}"><span><strong>${request.name}</strong><small>${request.email} · ${request.company}</small></span><b>Redefinir senha</b></button>`).join("")}</div>`:"";$("#usersTable").innerHTML=state.users.map(u=>`<tr><td><div style="display:flex;gap:10px;align-items:center"><div class="avatar">${initials(u.name)}</div><div><strong>${u.name}</strong><small>${u.email}</small></div></div></td><td>${u.company}</td><td>${u.role}</td><td class="permission-list">${u.globalApproval?'<strong>Aprovação geral</strong>':(u.specialties||[]).join(", ")||"Sem permissão de baixa"}</td><td><span class="status ${u.active?"baixada":"rejeitada"}">${u.active?"Ativo":"Inativo"}</span></td><td><div class="user-actions">${u.id!==state.currentUser.id?`<button class="reset-user-password" data-reset-password="${u.id}">Redefinir senha</button>`:""}<button class="toggle-status" data-user="${u.id}">${u.active?"Desativar":"Ativar"}</button>${u.email.endsWith(".teste@atlas-fico.local")?`<button class="delete-user" data-delete-user="${u.id}">Excluir teste</button>`:""}</div></td></tr>`).join("");$$('[data-reset-password],[data-request-reset]').forEach(button=>button.onclick=()=>openAdminPasswordReset(state.users.find(user=>user.id===+(button.dataset.resetPassword||button.dataset.requestReset))));$$('[data-user]').forEach(b=>b.onclick=async()=>{const u=state.users.find(x=>x.id===+b.dataset.user);if(u.id===state.currentUser.id){toast("Não é possível desativar o próprio usuário.");return}try{if(API_ENABLED)await api(`/users/${u.id}/status`,{method:"PATCH",body:JSON.stringify({active:!u.active})});u.active=!u.active;if(!API_ENABLED)save();renderUsers();toast(`Usuário ${u.active?"ativado":"desativado"}.`)}catch(error){toast(error.message)}});$$('[data-delete-user]').forEach(b=>b.onclick=async()=>{const u=state.users.find(x=>x.id===+b.dataset.deleteUser);if(!confirm(`Excluir definitivamente o perfil ${u.name}?`))return;try{await api(`/users/${u.id}`,{method:"DELETE"});state.users=state.users.filter(x=>x.id!==u.id);renderUsers();toast("Perfil de teste excluído.")}catch(error){toast(error.message)}})}

function bindIssueLinks(){$$('[data-issue]').forEach(el=>el.onclick=e=>{if(e.target.closest("[data-approve],[data-reject]"))return;const issue=state.issues.find(i=>i.id===+el.dataset.issue);openIssue(issue.id);if(state.currentUser.role==="Administrador")addAdminEditAction(issue)})}
function addAdminEditAction(issue){const actions=document.createElement("div");actions.className="drawer-actions admin-edit-actions";actions.innerHTML='<button class="btn ghost" type="button">Editar dados, responsáveis e fotos</button>';actions.querySelector("button").onclick=()=>openEditIssue(issue);$("#issueDrawerContent").append(actions)}
function openEditIssue(issue){closeDrawer();const form=$("#editIssueForm");form.elements.issueId.value=issue.id;form.elements.company.value=issue.company;form.elements.classification.value=issue.classification;form.elements.specialty.value=issue.type;form.elements.asset.value=issue.asset;form.elements.ficoOwner.value=issue.owner==="Não atribuído"?"":issue.owner;form.elements.contractorOwner.value=issue.contractor==="Não atribuído"?"":issue.contractor;form.elements.deadlineAt.value=issue.deadline||"";form.elements.kmStart.value=issue.kmStart||"";form.elements.kmEnd.value=issue.kmEnd||"";form.elements.description.value=issue.description;$("#editIssueDialog").showModal()}
function openIssue(id){const i=state.issues.find(x=>x.id===id);const auth=canApprove(i)||state.currentUser.role==="Administrador";const submit=canSubmitCorrection(i);const evidence=i.after?`<section class="evidence-section"><div class="section-label"><span>Comparação fotográfica</span><small>Confira enquadramento, local e serviço executado</small></div><div class="drawer-evidence-grid"><figure><figcaption>Antes</figcaption><img src="${i.before}" alt="Condição inicial da pendência ${i.id}"></figure><figure><figcaption>Depois</figcaption><img src="${i.after}" alt="Condição após correção da pendência ${i.id}"></figure></div></section>`:`<section class="evidence-section"><div class="section-label"><span>Evidência de abertura</span></div><figure class="drawer-single-evidence"><img src="${i.before}" alt="Condição inicial da pendência ${i.id}"></figure></section>`;$("#issueDrawerContent").innerHTML=`<div class="drawer-head"><div><p class="eyebrow">Pendência #${i.id}</p><h2>${i.type}</h2><span class="status ${statusClass(i.status)}">${i.status}</span></div><button class="icon-btn" id="closeDrawer">×</button></div><div class="drawer-body">${flowStepper(i.status)}${evidence}<div class="detail-grid"><div class="detail-item"><small>Empresa</small><strong>${i.company}</strong></div><div class="detail-item"><small>Classificação</small><strong>${i.classification}</strong></div><div class="detail-item"><small>Ativo e segmento</small><strong>${i.asset} · ${i.segment||"Não informado"}</strong></div><div class="detail-item"><small>Localização</small><strong>${i.km}</strong></div><div class="detail-item"><small>Prazo</small><strong>${formatDate(i.deadline)}</strong></div><div class="detail-item"><small>Fiscal responsável</small><strong>${i.owner}</strong></div><div class="detail-item"><small>Responsável contratada</small><strong>${i.contractor}</strong></div><div class="detail-item"><small>Data de abertura</small><strong>${formatDate(i.openedAt)}</strong></div></div><section class="drawer-description"><h3>Descrição completa</h3><p>${i.description}</p></section><h3>Histórico</h3><div class="timeline">${i.history.map((h,k)=>`<div class="timeline-item"><h4>${h}</h4><p>${k?"Hoje":"10/07/2026"} · Registro auditado</p></div>`).join("")}</div>${i.status==="Baixada"?`<button class="btn ghost certificate-btn" id="downloadCertificate">Baixar comprovante de encerramento</button>`:""}</div>${submit?`<div class="drawer-actions"><button class="btn primary" id="drawerCorrection">Informar correção e enviar foto</button></div>`:""}${i.status==="Aguardando validação"&&auth?`<div class="drawer-actions review-actions"><button class="btn danger" id="drawerReject">Rejeitar correção</button><button class="btn primary" id="drawerApprove">Revisar e confirmar baixa</button></div>`:""}`;$("#drawerOverlay").classList.remove("hidden");$("#issueDrawer").classList.remove("hidden");$("#closeDrawer").onclick=closeDrawer;if($("#downloadCertificate"))$("#downloadCertificate").onclick=async()=>{try{await downloadApi(`/issues/${i.id}/certificate.pdf`)}catch(error){toast(error.message)}};if($("#drawerCorrection"))$("#drawerCorrection").onclick=()=>openCorrection(i);if($("#drawerApprove"))$("#drawerApprove").onclick=()=>decide(id,true);if($("#drawerReject"))$("#drawerReject").onclick=()=>decide(id,false)}
function closeDrawer(){$("#drawerOverlay").classList.add("hidden");$("#issueDrawer").classList.add("hidden")}$("#drawerOverlay").onclick=closeDrawer;
function openCorrection(issue){closeDrawer();const form=$("#correctionForm");form.elements.issueId.value=issue.id;const fiscalNotice=state.currentUser.role!=="Contratada"?'<small class="fiscal-correction-notice">Após o envio, a pendência entrará na fila de validação. A baixa continuará exigindo uma confirmação separada.</small>':"";$("#correctionSummary").innerHTML=`<strong>Pendência #${issue.id} · ${issue.type}</strong><br>${issue.asset} · ${issue.company} · ${issue.km}${fiscalNotice}`;$("#correctionDialog").showModal()}
$$('.close-correction-dialog').forEach(b=>b.onclick=()=>$("#correctionDialog").close());
$("#correctionForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),issue=state.issues.find(i=>i.id===+f.get("issueId"));try{if(API_ENABLED){const file=e.target.elements.photo.files[0],coordinates=await currentCoordinates(),response=await api(`/issues/${issue.id}/correction`,{method:"POST",body:JSON.stringify({comment:f.get("comment"),photo_name:file.name,photo_data_url:await fileToDataUrl(file),captured_at:new Date().toISOString(),...coordinates,...issueVersion(issue)})});if(response.queued){issue.after=URL.createObjectURL(file);issue.status="Aguardando validação";issue.history.push(`Correção salva offline por ${state.currentUser.name}`)}else await hydrateFromApi()}else{issue.after=photoB;issue.status="Aguardando validação";issue.history.push(`Correção informada por ${state.currentUser.name}: ${f.get("comment")}`);save()}e.target.reset();$("#correctionDialog").close();renderAll();await updateSyncStatus();showView("issues");toast(navigator.onLine?`Correção da pendência #${issue.id} enviada para validação.`:"Correção salva no aparelho e aguardando conexão.")}catch(error){if(error.status===409&&error.body?.conflict)await hydrateFromApi();toast(error.message)}};

$("#newIssueBtn").onclick=()=>$("#issueDialog").showModal();$$('.close-dialog').forEach(b=>b.onclick=()=>$("#issueDialog").close());$("#issueForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);try{let id;if(API_ENABLED){const file=e.target.elements.photo.files[0],coordinates=await currentCoordinates(),openedAt=new Date().toISOString().slice(0,10),response=await api("/issues",{method:"POST",body:JSON.stringify({company:f.get("company"),asset:f.get("asset"),specialty:f.get("type"),classification:f.get("classification"),description:f.get("description"),km_start:f.get("kmStart"),km_end:f.get("kmEnd"),deadline_at:f.get("deadline"),opened_at:openedAt,fico_owner:f.get("ficoOwner"),photo_name:file.name,photo_data_url:await fileToDataUrl(file),captured_at:new Date().toISOString(),...coordinates})});id=response.id||response.temp_id;if(response.queued)state.issues.unshift({id,company:f.get("company"),asset:f.get("asset"),segment:"A definir",kmStart:f.get("kmStart"),kmEnd:f.get("kmEnd"),km:`${f.get("kmStart")} a ${f.get("kmEnd")}`,type:f.get("type"),classification:f.get("classification"),description:f.get("description"),openedAt,deadline:f.get("deadline"),status:"Aberta",owner:f.get("ficoOwner"),contractor:"Não atribuído",before:URL.createObjectURL(file),after:null,latitude:coordinates.latitude||null,longitude:coordinates.longitude||null,updatedAt:null,history:[`Pendência registrada offline por ${state.currentUser.name}`]});else await hydrateFromApi()}else{id=Math.max(...state.issues.map(i=>i.id))+1;state.issues.unshift({id,company:f.get("company"),asset:f.get("asset"),segment:"A definir",km:`${f.get("kmStart")} a ${f.get("kmEnd")}`,type:f.get("type"),classification:f.get("classification"),description:f.get("description"),deadline:f.get("deadline"),status:"Aberta",owner:f.get("ficoOwner"),contractor:"Não atribuído",before:photoA,after:null,history:[`Pendência registrada por ${state.currentUser.name}`]});save()}e.target.reset();$("#issueDialog").close();renderAll();await updateSyncStatus();showView("issues");toast(navigator.onLine?`Pendência #${id} registrada.`:"Pendência salva no aparelho e aguardando conexão.")}catch(error){toast(error.message)}};
$("#specialtyChecks").innerHTML=specialties.map(s=>`<label><input type="checkbox" name="specialty" value="${s}">${s}</label>`).join("");$("#newUserBtn").onclick=()=>$("#userDialog").showModal();$$('.close-user-dialog').forEach(b=>b.onclick=()=>$("#userDialog").close());$("#userForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);if(state.users.some(u=>u.email===f.get("email"))){toast("Já existe um usuário com este e-mail.");return}try{if(API_ENABLED){await api("/users",{method:"POST",body:JSON.stringify({name:f.get("name"),email:f.get("email"),company:f.get("company"),role:f.get("role"),global_approval:f.get("globalApproval")==="on",specialties:f.getAll("specialty"),temporary_password:f.get("temporaryPassword")})});await hydrateFromApi()}else{state.users.push({id:Date.now(),name:f.get("name"),email:f.get("email"),company:f.get("company"),role:f.get("role"),globalApproval:f.get("globalApproval")==="on",specialties:f.getAll("specialty"),active:true});save()}e.target.reset();$("#userDialog").close();renderUsers();toast("Usuário cadastrado com senha temporária.")}catch(error){toast(error.message)}};
$$('.close-reset-password').forEach(button=>button.onclick=()=>$("#resetPasswordDialog").close());$("#resetPasswordForm").onsubmit=async event=>{event.preventDefault();const form=new FormData(event.target),userId=+form.get("userId");try{await api(`/users/${userId}/reset-password`,{method:"POST",body:JSON.stringify({temporary_password:form.get("temporaryPassword")})});event.target.reset();$("#resetPasswordDialog").close();await hydrateFromApi();renderUsers();toast("Senha temporária definida. O usuário foi desconectado.")}catch(error){toast(error.message)}};

$$('.close-decision-dialog').forEach(b=>b.onclick=()=>$("#decisionDialog").close());$("#decisionForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target);try{await completeDecision(+f.get("issueId"),false,f.get("comment"));e.target.reset();$("#decisionDialog").close();closeDrawer()}catch(error){toast(error.message)}};
$$('.close-approval-dialog').forEach(button=>button.onclick=()=>$("#approvalDialog").close());$("#approvalForm").onsubmit=async event=>{event.preventDefault();const form=new FormData(event.target);if(!form.get("reviewed")){toast("Confirme que revisou os dados e as duas fotos.");return}try{await completeDecision(+form.get("issueId"),true,form.get("comment"));event.target.reset();$("#approvalDialog").close();closeDrawer()}catch(error){toast(error.message)}};

$("#passwordForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),next=f.get("newPassword");if(next!==f.get("confirmPassword")){toast("A confirmação não corresponde à nova senha.");return}try{await api("/change-password",{method:"POST",body:JSON.stringify({current_password:f.get("currentPassword"),new_password:next})});await AtlasOffline.clearIdentity(state.currentUser.email);localStorage.removeItem("atlas-api-token");toast("Senha alterada. Entre novamente com a nova senha.");setTimeout(()=>location.reload(),1400)}catch(error){toast(error.message)}};

$$('.close-edit-dialog').forEach(b=>b.onclick=()=>$("#editIssueDialog").close());$("#editIssueForm").onsubmit=async e=>{e.preventDefault();const f=new FormData(e.target),id=+f.get("issueId"),issue=state.issues.find(i=>i.id===id);try{if(API_ENABLED){await api(`/issues/${id}`,{method:"PATCH",body:JSON.stringify({company:f.get("company"),classification:f.get("classification"),specialty:f.get("specialty"),asset:f.get("asset"),fico_owner:f.get("ficoOwner"),contractor_owner:f.get("contractorOwner"),deadline_at:f.get("deadlineAt")||null,km_start:f.get("kmStart"),km_end:f.get("kmEnd"),description:f.get("description")})});const file=e.target.elements.historicalPhoto.files[0];if(file)await api(`/issues/${id}/evidence`,{method:"POST",body:JSON.stringify({kind:f.get("evidenceKind"),photo_name:file.name,photo_data_url:await fileToDataUrl(file),captured_at:new Date().toISOString()})});await hydrateFromApi()}else{issue.company=f.get("company");issue.classification=f.get("classification");issue.type=f.get("specialty");issue.asset=f.get("asset");issue.owner=f.get("ficoOwner")||"Não atribuído";issue.contractor=f.get("contractorOwner")||"Não atribuído";issue.deadline=f.get("deadlineAt");issue.kmStart=f.get("kmStart");issue.kmEnd=f.get("kmEnd");issue.km=[issue.kmStart,issue.kmEnd].filter(Boolean).join(" a ");issue.description=f.get("description");issue.history.push(`Pendência editada por ${state.currentUser.name}`);save()}e.target.reset();$("#editIssueDialog").close();renderAll();showView("issues");toast("Pendência e responsabilidades atualizadas.")}catch(error){toast(error.message)}};

const escapeHtml=value=>String(value??"").replace(/[&<>'"]/g,character=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"})[character]);
const formatMoment=value=>value?new Intl.DateTimeFormat("pt-BR",{dateStyle:"short",timeStyle:"short"}).format(new Date(value)):"Ainda não sincronizado";
function syncOperationInfo(item){if(item.path==="/issues")return {title:"Nova pendência",issue:`Registro temporário ${-item.id}`,detail:`${item.body.company} · ${item.body.asset}`};const match=item.path.match(/^\/issues\/(-?\d+)\/(correction|decision)$/);if(!match)return {title:"Operação",issue:item.path,detail:""};if(match[2]==="correction")return {title:"Foto de correção",issue:`Pendência #${match[1]}`,detail:item.body.comment||"Correção registrada em campo"};return {title:item.body.decision==="approve"?"Aprovação de baixa":"Rejeição da correção",issue:`Pendência #${match[1]}`,detail:item.body.comment||"Decisão registrada em campo"}}
async function renderSyncCenter(){if(!window.AtlasOffline||!$("#syncQueue"))return;const items=await AtlasOffline.pending(),info=await AtlasOffline.stats();$("#syncOverview").innerHTML=`<div><small>Na fila</small><strong>${info.pending}</strong><span>operações neste aparelho</span></div><div><small>Conflitos</small><strong>${info.conflicts}</strong><span>exigem decisão</span></div><div><small>Falhas de envio</small><strong>${info.errors}</strong><span>podem ser tentadas novamente</span></div><div><small>Último envio</small><strong class="sync-date">${formatMoment(info.lastSuccessAt)}</strong><span>${navigator.onLine?"conectado à internet":"trabalhando offline"}</span></div>`;$("#syncAllBtn").disabled=!navigator.onLine||!items.length;$("#syncQueue").innerHTML=items.length?items.map(item=>{const operation=syncOperationInfo(item),stateClass=item.conflict?"conflict":item.lastError?"error":"pending",stateLabel=item.conflict?"Conflito de versão":item.lastError?"Falha no envio":"Aguardando envio",preview=item.body.photo_data_url?`<img class="sync-photo" src="${item.body.photo_data_url}" alt="Foto aguardando sincronização">`:"";return `<article class="sync-card ${stateClass}" data-sync-item="${item.id}"><div class="sync-card-main">${preview}<div><div class="sync-card-title"><span class="sync-state">${stateLabel}</span><small>${formatMoment(item.createdAt)}</small></div><h3>${operation.title}</h3><strong>${operation.issue}</strong><p>${escapeHtml(operation.detail)}</p>${item.lastError?`<div class="sync-error">${escapeHtml(item.lastError)}</div>`:""}${item.conflict?`<div class="conflict-compare"><div><small>Versão no aparelho</small><strong>${escapeHtml(item.body.base_updated_at?formatMoment(item.body.base_updated_at):"registro novo")}</strong></div><div><small>Versão no servidor</small><strong>${escapeHtml(item.server?.status||"alterada")}</strong><span>${escapeHtml(formatMoment(item.server?.updated_at))}</span></div></div>`:""}</div></div><div class="sync-card-actions">${item.conflict?`<button class="btn ghost" data-sync-discard="${item.id}">Usar versão do servidor</button><button class="btn primary" data-sync-force="${item.id}">Reaplicar minha alteração</button>`:`<button class="btn ghost" data-sync-discard="${item.id}">Descartar</button><button class="btn primary" data-sync-retry="${item.id}" ${navigator.onLine?"":"disabled"}>Enviar agora</button>`}</div></article>`}).join(""):`<div class="sync-empty"><span>✓</span><h3>Fila sincronizada</h3><p>Este aparelho não possui operações aguardando envio.</p></div>`;$$('[data-sync-retry]').forEach(button=>button.onclick=async()=>{await AtlasOffline.retry(+button.dataset.syncRetry);await syncNow(+button.dataset.syncRetry)});$$('[data-sync-force]').forEach(button=>button.onclick=async()=>{await AtlasOffline.retry(+button.dataset.syncForce,true);await syncNow(+button.dataset.syncForce)});$$('[data-sync-discard]').forEach(button=>button.onclick=async()=>{if(button.dataset.armed!=="true"){button.dataset.armed="true";button.textContent="Clique novamente para confirmar";setTimeout(()=>{button.dataset.armed="false";button.textContent=button.closest('.sync-card').classList.contains('conflict')?"Usar versão do servidor":"Descartar"},3500);return}await AtlasOffline.discard(+button.dataset.syncDiscard);await hydrateFromApi();renderAll();await updateSyncStatus();toast("Operação local descartada. A versão do servidor foi preservada.")})}

let issuesLeafletMap=null,issuesMarkerLayer=null,userLocationMarker=null;
const kmNumber=value=>{const match=String(value||"").match(/(\d+)(?:\D+(\d{1,3}))?/);return match?Number(match[1])+Number(match[2]||0)/1000:Number.POSITIVE_INFINITY};
function filteredMapIssues(){return state.issues.filter(issue=>(!$("#mapCompanyFilter").value||issue.company===$("#mapCompanyFilter").value)&&(!$("#mapStatusFilter").value||issue.status===$("#mapStatusFilter").value)&&(!$("#mapTypeFilter").value||issue.type===$("#mapTypeFilter").value))}
function renderMap(){if(!$("#issuesMap"))return;setFilterOptions("#mapCompanyFilter","Todas as empresas",[...new Set(state.issues.map(issue=>issue.company))]);setFilterOptions("#mapStatusFilter","Todos os status",[...new Set(state.issues.map(issue=>issue.status))]);setFilterOptions("#mapTypeFilter","Todas as especialidades",[...new Set(state.issues.map(issue=>issue.type))]);const issues=filteredMapIssues(),located=issues.filter(issue=>Number.isFinite(issue.latitude)&&Number.isFinite(issue.longitude));if(window.L){if(!issuesLeafletMap){issuesLeafletMap=L.map("issuesMap",{zoomControl:true}).setView([-15.5,-48.5],5);L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{maxZoom:19,attribution:'&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'}).addTo(issuesLeafletMap);issuesMarkerLayer=L.layerGroup().addTo(issuesLeafletMap);issuesLeafletMap.on("popupopen",()=>$$('[data-map-open]').forEach(button=>button.onclick=()=>openIssue(+button.dataset.mapOpen)))}issuesMarkerLayer.clearLayers();const bounds=[];located.forEach(issue=>{const color=issue.status==="Baixada"?"#388c69":issue.status==="Aguardando validação"?"#ef9a34":"#3578bc",marker=L.circleMarker([issue.latitude,issue.longitude],{radius:8,color:"#fff",weight:2,fillColor:color,fillOpacity:1}).bindPopup(`<div class="map-popup"><small>#${issue.id} · ${escapeHtml(issue.company)}</small><strong>${escapeHtml(issue.asset)}</strong><span>${escapeHtml(issue.type)} · ${escapeHtml(issue.status)}</span><button type="button" data-map-open="${issue.id}">Abrir pendência</button></div>`);marker.addTo(issuesMarkerLayer);bounds.push([issue.latitude,issue.longitude])});if(bounds.length>1)issuesLeafletMap.fitBounds(bounds,{padding:[30,30],maxZoom:15});else if(bounds.length===1)issuesLeafletMap.setView(bounds[0],15);setTimeout(()=>issuesLeafletMap.invalidateSize(),80)}$("#mapEmpty").classList.toggle("hidden",located.length>0);const ordered=[...issues].sort((a,b)=>kmNumber(a.kmStart)-kmNumber(b.kmStart)||a.id-b.id);$("#linearMapCount").textContent=`${issues.length} registro${issues.length===1?"":"s"}`;$("#linearMap").innerHTML=ordered.slice(0,300).map(issue=>`<button type="button" class="linear-map-item" data-linear-issue="${issue.id}"><span class="linear-km">${escapeHtml(issue.kmStart||"KM não informado")}</span><i class="linear-node ${statusClass(issue.status)}"></i><span><strong>#${issue.id} · ${escapeHtml(issue.asset)}</strong><small>${escapeHtml(issue.company)} · ${escapeHtml(issue.type)} · ${escapeHtml(issue.status)}</small></span></button>`).join("")+(ordered.length>300?`<p class="linear-limit">Mostrando os primeiros 300 registros. Use os filtros para reduzir a carteira.</p>`:"");$$('[data-linear-issue]').forEach(button=>button.onclick=()=>openIssue(+button.dataset.linearIssue))}

async function loadBackups(){if(state.currentUser?.role!=="Administrador"||!$("#backupList"))return;try{state.backups=await api("/admin/backups");renderBackups()}catch(error){$("#backupList").innerHTML=`<div class="sync-empty"><h3>Backups indisponíveis</h3><p>${escapeHtml(error.message)}</p></div>`}}
function renderBackups(){$("#backupList").innerHTML=state.backups.length?state.backups.map(backup=>`<article class="backup-card"><div class="backup-icon">▣</div><div><small>Ponto #${backup.id}</small><h3>${escapeHtml(backup.label)}</h3><p>${backup.issue_count} pendências · criado por ${escapeHtml(backup.created_by_name)} em ${formatMoment(backup.created_at)}</p></div><div class="backup-actions"><button class="btn ghost" data-backup-download="${backup.id}">Baixar JSON</button><button class="btn danger-soft" data-backup-restore="${backup.id}">Restaurar</button></div></article>`).join(""):`<div class="sync-empty"><span>▣</span><h3>Nenhum ponto criado</h3><p>Crie o primeiro backup antes de uma importação ou alteração administrativa importante.</p></div>`;$$('[data-backup-download]').forEach(button=>button.onclick=async()=>{try{await downloadApi(`/admin/backups/${button.dataset.backupDownload}/download`)}catch(error){toast(error.message)}});$$('[data-backup-restore]').forEach(button=>button.onclick=async()=>{const info=await AtlasOffline.stats();if(info.pending){toast("Sincronize ou descarte a fila deste aparelho antes de restaurar um backup.");showView("sync");return}const backup=state.backups.find(item=>item.id===+button.dataset.backupRestore),form=$("#restoreBackupForm");form.reset();form.elements.backupId.value=backup.id;$("#restoreBackupSummary").innerHTML=`<strong>${escapeHtml(backup.label)}</strong><span>${backup.issue_count} pendências · ${formatMoment(backup.created_at)}</span>`;$("#restoreBackupDialog").showModal()})}

