$("#mapLocateBtn").addEventListener("click",async()=>{if(!window.L){toast("O mapa geográfico precisa ser carregado uma vez com internet. A visão por KM continua disponível offline.");return}const coordinates=await currentCoordinates();if(!coordinates.latitude){toast("Não foi possível obter a localização deste aparelho.");return}if(!issuesLeafletMap)renderMap();if(userLocationMarker)userLocationMarker.remove();userLocationMarker=L.circleMarker([coordinates.latitude,coordinates.longitude],{radius:9,color:"#17324d",weight:3,fillColor:"#fff",fillOpacity:1}).addTo(issuesLeafletMap).bindPopup("Sua localização");issuesLeafletMap.setView([coordinates.latitude,coordinates.longitude],15);userLocationMarker.openPopup()});
$("#syncAllBtn").addEventListener("click",()=>syncNow());
$("#createBackupBtn").addEventListener("click",async()=>{if(!navigator.onLine){toast("Conecte-se à internet para criar um ponto de recuperação.");return}const button=$("#createBackupBtn"),original=button.textContent;button.disabled=true;button.textContent="Criando backup...";try{const response=await api("/admin/backups",{method:"POST",body:JSON.stringify({})});toast(`Ponto de recuperação criado com ${response.issue_count} pendências.`);await loadBackups()}catch(error){toast(error.message)}finally{button.disabled=false;button.textContent=original}});
